function throttle(fn, limit) {
  let inThrottle = false;
  let lastArgs = null;
  let lastContext = null;

  return function(...args) {
    if (inThrottle) {
      lastArgs = args;
      lastContext = this;
      return;
    }

    fn.apply(this, args);
    inThrottle = true;

    setTimeout(() => {
      inThrottle = false;
      if (lastArgs) {
        fn.apply(lastContext, lastArgs);
        lastArgs = null;
        lastContext = null;
      }
    }, limit);
  };
}

// Usage: scroll handler
const updateScrollIndicator = throttle(() => {
  const scrollPercent = window.scrollY / (document.body.scrollHeight - window.innerHeight);
  document.getElementById('progress').style.width = `${scrollPercent * 100}%`;
}, 100);

window.addEventListener('scroll', updateScrollIndicator);
// Updates at most every 100ms, not on every scroll pixel

function leadingDebounce(fn, delay) {
  let timer = null;
  let canCall = true;

  return function(...args) {
    const context = this;

    if (canCall) {
      fn.apply(context, args);
      canCall = false;
    }

    clearTimeout(timer);
    timer = setTimeout(() => {
      canCall = true;
    }, delay);
  };
}

// Usage: prevent double submit
const saveButton = document.getElementById('save');
const handleSave = leadingDebounce(async () => {
  await saveDocument();
  showToast('Saved!');
}, 2000);

saveButton.addEventListener('click', handleSave);
// First click saves immediately, then blocks for 2 seconds

function debounce(fn, delay) {
  let timer = null;

  const debounced = function(...args) {
    const context = this;
    clearTimeout(timer);
    timer = setTimeout(() => fn.apply(context, args), delay);
  };

  debounced.cancel = function() {
    clearTimeout(timer);
    timer = null;
  };

  debounced.flush = function() {
    if (timer) {
      clearTimeout(timer);
      fn.apply(this, arguments);
      timer = null;
    }
  };

  return debounced;
}

